B.D8=s(["The Sun is a star at the center of our Solar System.","It provides the heat and light that make life on Earth possible.","About 1.3 million Earths could fit inside the Sun.","Its gravity holds every planet in orbit."],t.s)
B.FH=new A.aZ(B.b7,["Sun","Center of the Solar System",B.D8,"1.989 \xd7 10^30 kg","274 m/s\xb2","1,392,700 km","25 Earth days (equator)","25 Earth days","0 km (center)"],t.e)
B.CX=s(["Mercury is the smallest planet in the Solar System.","It is the closest planet to the Sun.","A day on Mercury is longer than its year.","Mercury has almost no atmosphere to trap heat."],t.s)
B.FJ=new A.aZ(B.b7,["Mercury","1st planet from the Sun",B.CX,"3.285 \xd7 10^23 kg","3.7 m/s\xb2","4,879 km","88 Earth days","59 Earth days","57.9 million km"],t.e)
B.D9=s(["Venus is the hottest planet because of its thick atmosphere.","It spins in the opposite direction to most planets.","Venus is often called Earth's twin because of its size.","Its clouds are made of sulfuric acid."],t.s)
B.FG=new A.aZ(B.b7,["Venus","2nd planet from the Sun",B.D9,"4.867 \xd7 10^24 kg","8.87 m/s\xb2","12,104 km","225 Earth days","243 Earth days","108.2 million km"],t.e)
B.DD=s(["Earth is the only known planet with life.","Liquid water covers most of the planet.","Earth has one natural moon.","Its atmosphere protects life and keeps temperatures stable."],t.s)
B.q4=new A.aZ(B.b7,["Earth","3rd planet from the Sun",B.DD,"5.972 \xd7 10^24 kg","9.8 m/s\xb2","12,742 km","365.25 days","24 hours","149.6 million km"],t.e)
B.Dd=s(["Mars is called the Red Planet because of iron-rich dust.","It has the tallest volcano in the Solar System.","Evidence suggests Mars once had flowing water.","Mars has two small moons named Phobos and Deimos."],t.s)
B.FL=new A.aZ(B.b7,["Mars","4th planet from the Sun",B.Dd,"6.39 \xd7 10^23 kg","3.71 m/s\xb2","6,779 km","687 Earth days","24.6 hours","227.9 million km"],t.e)
B.DX=s(["Jupiter is the largest planet in the Solar System.","It is a gas giant made mostly of hydrogen and helium.","The Great Red Spot is a giant storm larger than Earth.","Jupiter has many moons, including Ganymede."],t.s)
B.FI=new A.aZ(B.b7,["Jupiter","5th planet from the Sun",B.DX,"1.898 \xd7 10^27 kg","24.79 m/s\xb2","139,820 km","11.86 Earth years","9.9 hours","778.5 million km"],t.e)
B.D1=s(["Saturn is famous for its bright rings.","Its rings are made of ice, dust, and rocky pieces.","Saturn is so light it could float in water.","It has a large moon called Titan."],t.s)
B.FF=new A.aZ(B.b7,["Saturn","6th planet from the Sun",B.D1,"5.683 \xd7 10^26 kg","10.44 m/s\xb2","116,460 km","29.46 Earth years","10.7 hours","1.4 billion km"],t.e)
B.DU=s(["Uranus rotates on its side compared with most planets.","It is an ice giant with a cold atmosphere.","The planet looks blue-green because of methane gas.","Uranus has faint rings and many moons."],t.s)
B.FK=new A.aZ(B.b7,["Uranus","7th planet from the Sun",B.DU,"8.681 \xd7 10^25 kg","8.87 m/s\xb2","50,724 km","84 Earth years","17.2 hours","2.9 billion km"],t.e)
B.Dm=s(["Neptune is the farthest major planet from the Sun.","It has some of the strongest winds in the Solar System.","Neptune is an ice giant with a deep blue color.","It was discovered using mathematics before telescopes confirmed it."],t.s)
